from typing import Dict, Any, List

def generate_terraform_vars(config: Dict[str, Any]) -> str:
    """
    Generate Terraform variable definitions from a configuration dict.
    """
    blocks = []

    for var_name, var_config in config.items():
        lines = [f'variable "{var_name}" {{']

        # Type
        var_type = var_config.get('type', 'string')
        lines.append(f'  type        = {var_type}')

        # Default value (if present)
        if 'default' in var_config:
            default = var_config['default']
            if isinstance(default, bool):
                default_str = 'true' if default else 'false'
            elif isinstance(default, str):
                default_str = f'"{default}"'
            elif isinstance(default, list):
                items = ', '.join(f'"{item}"' if isinstance(item, str) else str(item) for item in default)
                default_str = f'[{items}]'
            else:
                default_str = str(default)
            lines.append(f'  default     = {default_str}')

        # Description
        if 'description' in var_config:
            lines.append(f'  description = "{var_config["description"]}"')

        lines.append('}')
        blocks.append('\n'.join(lines))

    return '\n\n'.join(blocks)

import os
from typing import Any, Dict
import yaml

class ConfigLoader:
    """
    Loads configuration from YAML files with environment variable substitution.
    """

    def __init__(self, config_dir: str = 'config'):
        self.config_dir = config_dir

    def load(self, environment: str) -> Dict[str, Any]:
        """
        Load configuration for an environment.
        """
        config_path = f"{self.config_dir}/{environment}.yaml"

        with open(config_path, 'r') as f:
            config = yaml.safe_load(f)

        return self.substitute_env_vars(config)

    def substitute_env_vars(self, obj: Any) -> Any:
        """
        Recursively substitute ${VAR_NAME} patterns with environment values.
        """
        if isinstance(obj, str):
            # Only substitute if entire string is ${VAR}
            if obj.startswith('${') and obj.endswith('}'):
                var_name = obj[2:-1]
                return os.environ.get(var_name, obj)
            return obj
        elif isinstance(obj, dict):
            return {k: self.substitute_env_vars(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [self.substitute_env_vars(item) for item in obj]
        return obj

    def validate_required(self, config: Dict, required: list) -> list:
        """
        Validate that required keys exist in config.
        """
        missing = []
        for key in required:
            parts = key.split('.')
            current = config
            try:
                for part in parts:
                    current = current[part]
            except (KeyError, TypeError):
                missing.append(key)
        return missing

from typing import List, Dict, Any
import json

def generate_quantum_iam_policy(
    backends: List[str],
    s3_bucket: str,
    enable_hardware: bool = False,
    readonly: bool = False
) -> str:
    """
    Generate AWS IAM policy for quantum backend access.
    """
    statements = []

    if 'braket' in backends:
        # Read actions (always allowed)
        braket_read_actions = [
            'braket:GetDevice',
            'braket:SearchDevices',
            'braket:GetQuantumTask',
            'braket:SearchQuantumTasks'
        ]

        statements.append({
            'Sid': 'BraketReadAccess',
            'Effect': 'Allow',
            'Action': braket_read_actions,
            'Resource': generate_resource_arns('braket', enable_hardware)
        })

        # Write actions (if not readonly)
        if not readonly:
            braket_write_actions = [
                'braket:CreateQuantumTask',
                'braket:CancelQuantumTask'
            ]
            statements.append({
                'Sid': 'BraketWriteAccess',
                'Effect': 'Allow',
                'Action': braket_write_actions,
                'Resource': generate_resource_arns('braket', enable_hardware)
            })

        # S3 access for results
        s3_read_actions = ['s3:GetObject', 's3:ListBucket']
        statements.append({
            'Sid': 'S3ReadAccess',
            'Effect': 'Allow',
            'Action': s3_read_actions,
            'Resource': [s3_bucket, f'{s3_bucket}/*']
        })

        if not readonly:
            statements.append({
                'Sid': 'S3WriteAccess',
                'Effect': 'Allow',
                'Action': ['s3:PutObject'],
                'Resource': f'{s3_bucket}/*'
            })

    if 'secrets' in backends:
        statements.append({
            'Sid': 'SecretsReadAccess',
            'Effect': 'Allow',
            'Action': [
                'secretsmanager:GetSecretValue',
                'secretsmanager:DescribeSecret'
            ],
            'Resource': 'arn:aws:secretsmanager:*:*:secret:quantum/*'
        })

    policy = {
        'Version': '2012-10-17',
        'Statement': statements
    }

    return json.dumps(policy, indent=2)

def generate_resource_arns(
    backend: str,
    enable_hardware: bool
) -> List[str]:
    """
    Generate appropriate resource ARNs for a backend.
    """
    if backend == 'braket':
        if enable_hardware:
            return ['*']
        else:
            return [
                'arn:aws:braket:::device/quantum-simulator/amazon/sv1',
                'arn:aws:braket:::device/quantum-simulator/amazon/tn1',
                'arn:aws:braket:::device/quantum-simulator/amazon/dm1',
                'arn:aws:braket:*:*:quantum-task/*'
            ]
    return ['*']

from dataclasses import dataclass
from typing import List, Dict, Any, Optional
import re

@dataclass
class ValidationResult:
    valid: bool
    errors: List[str]
    warnings: List[str]

class GitOpsValidator:
    """
    Validates GitOps workflow configurations.
    """

    def __init__(self):
        self.required_files = [
            'main.tf',
            'variables.tf',
            'outputs.tf'
        ]
        self.sensitive_patterns = [
            'password',
            'secret',
            'token',
            'key',
            'credential'
        ]

    def validate_terraform_structure(
        self,
        files: List[str]
    ) -> ValidationResult:
        """
        Validate that required Terraform files exist.
        """
        errors = []
        warnings = []

        for required in self.required_files:
            if required not in files:
                errors.append(f"Missing required file: {required}")

        # Check for terraform.tfvars (warning if present, might contain secrets)
        if 'terraform.tfvars' in files:
            warnings.append("terraform.tfvars found - ensure no secrets are committed")

        # Check for .terraform directory (should not be committed)
        if any(f.startswith('.terraform') for f in files):
            errors.append(".terraform directory should not be committed")

        return ValidationResult(
            valid=len(errors) == 0,
            errors=errors,
            warnings=warnings
        )

    def check_for_hardcoded_secrets(
        self,
        content: str
    ) -> List[str]:
        """
        Check for potential hardcoded secrets in terraform content.
        """
        warnings = []
        lines = content.split('\n')

        for i, line in enumerate(lines, 1):
            line_lower = line.lower()

            for pattern in self.sensitive_patterns:
                # Look for pattern = "value" (not pattern = var.xxx)
                regex = rf'{pattern}\s*=\s*"[^"]+"'
                if re.search(regex, line_lower):
                    # Exclude if it references a variable
                    if 'var.' not in line and '${' not in line:
                        warnings.append(
                            f"Line {i}: Possible hardcoded {pattern} detected"
                        )

        return warnings

    def validate_backend_config(
        self,
        config: Dict[str, Any]
    ) -> ValidationResult:
        """
        Validate Terraform backend configuration.
        """
        errors = []
        warnings = []

        if 'bucket' not in config:
            errors.append("Backend config missing 'bucket'")

        if 'key' not in config:
            errors.append("Backend config missing 'key'")

        if not config.get('encrypt', False):
            warnings.append("Backend encryption is not enabled")

        if not config.get('dynamodb_table'):
            warnings.append("No DynamoDB table for state locking")

        return ValidationResult(
            valid=len(errors) == 0,
            errors=errors,
            warnings=warnings
        )
